const DEFAULT_ICON: ServiceIconRule = {
  keyword: '',
  src: "data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' width='1em' height='1em' viewBox='0 0 24 24'><path fill='currentColor' d='M21 2H3c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h18c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2m0 18H3V6h18z'/></svg>",
  width: 18,
  height: 18,
};

export function serviceIconFor(serviceName: string) {
  const lower = serviceName.toLowerCase();
  const rule = SERVICE_ICON_RULES.find((candidate) =>
    lower.includes(candidate.keyword),
  );
  return rule ?? DEFAULT_ICON;
}
